class CheckoutSuggestionProduct { const CheckoutSuggestionProduct({required this.id,required this.name,required this.price,required this.imageUrl,required this.inStock}); final int id; final String name; final String price; final String imageUrl; final bool inStock; factory CheckoutSuggestionProduct.fromJson(Map<String,dynamic> json)=>CheckoutSuggestionProduct(id:int.tryParse('${json['id']}')??0,name:'${json['name']??''}',price:'${json['price']??''}',imageUrl:'${json['image_url']??''}',inStock:json['in_stock']!=false); }
class CheckoutSuggestions { const CheckoutSuggestions({this.enabled=false,this.title='',this.buttonLabel='Add',this.buttonColor='#2F806E',this.buttonTextColor='#FFFFFF',this.products=const[]}); final bool enabled; final String title; final String buttonLabel; final String buttonColor; final String buttonTextColor; final List<CheckoutSuggestionProduct> products; factory CheckoutSuggestions.fromJson(Map<String,dynamic> json){final raw=json['products'];return CheckoutSuggestions(enabled:json['enabled']==true||json['enabled']==1,title:'${json['title']??''}',buttonLabel:'${json['button_label']??'Add'}',buttonColor:'${json['button_color']??'#2F806E'}',buttonTextColor:'${json['button_text_color']??'#FFFFFF'}',products:raw is List?raw.whereType<Map>().map((e)=>CheckoutSuggestionProduct.fromJson(Map<String,dynamic>.from(e))).where((e)=>e.id>0).toList():const[]);}}
